def history_to_messages(history: History,
                        system: Optional[str] = None,
                        roles: Optional[List[List[str]]] = None) -> 'Messages':
    """
    history: [['query1', 'response1'], ['query2', 'response2']]
        or [['query1', 'response1'], ['query2', None]]
    """
    messages = []
    if not roles:
        roles = [['user', 'assistant']] * len(history)
    else:
        assert len(roles) == len(history), f'len(roles): {len(roles)}, len(history): {len(history)}'
    if system is not None:
        messages.append({'role': 'system', 'content': system})

    for role, h in zip(roles, history):
        assert isinstance(h, (list, tuple))
        if h[0] is not None:
            messages.append({'role': role[0], 'content': h[0]})
        if h[1] is not None:
            messages.append({'role': role[1], 'content': h[1]})
    return messages


def messages_to_history(messages: 'Messages') -> Dict[str, Any]:
    system = None
    messages = messages.copy()
    if messages[0]['role'] == 'system':
        system = messages[0]['content']
        messages = messages[1::]
    if len(messages) % 2 == 1:
        messages.append({'role': 'assistant', 'content': None})
    history = []
    history_roles = []
    for user_message, assistant_message in zip(messages[::2], messages[1::2]):
        assert user_message['role'] in {'tool', 'user'}, f'user_message {user_message}'
        assert assistant_message['role'] == 'assistant', f'assistant_message: {assistant_message}'
        history.append([user_message['content'], assistant_message['content']])
        history_roles.append([user_message['role'], assistant_message['role']])
    query, response = history.pop() if history else (None, None)
    query_role = history_roles.pop()[0] if history_roles else None
    return {
        'history': history,
        'history_roles': history_roles,
        'query': query,
        'query_role': query_role,
        'response': response,
        'system': system,
    }


def update_generation_config_eos_token(generation_config, template):
    if generation_config is None:
        return
    stop_words = template.template_meta.stop_words
    eos_token_id = generation_config.eos_token_id
    if eos_token_id is None:
        eos_token_id = []
    elif isinstance(eos_token_id, int):
        eos_token_id = [eos_token_id]
    modified = False
    for stop_word in stop_words:
        if stop_word is None:
            continue
        if isinstance(stop_word, str):
            stop_word = template._tokenize(stop_word)
        if isinstance(stop_word, (list, tuple)) and len(stop_word) == 1 and stop_word[0] not in eos_token_id:
            eos_token_id.append(stop_word[0])
            modified = True
    if modified:
        generation_config.eos_token_id = eos_token_id

def _add_default_tags(inputs: StdTemplateInputs):
    total_content = []
    for message in inputs.messages:
        content = message['content'] or ''
        if not isinstance(content, str):
            if message['role'] == 'user':
                # Give up adding the default tag
                return
            elif message['role'] == 'assistant':
                continue
        total_content.append(content)
    total_content = '\n'.join(total_content)
    if inputs.system:
        total_content = f'{inputs.system}\n{total_content}'
    for media_type in ['image', 'audio', 'video']:
        media_key, media_tag = f'{media_type}s', f'<{media_type}>'
        medias = getattr(inputs, media_key)
        if not isinstance(medias, list):
            medias = [medias]
        if medias:
            num_media_tags = len(re.findall(media_tag, total_content))
            num_media = len(medias)
            num_new_tags = num_media - num_media_tags
            if num_new_tags > 0:
                inputs.messages[0]['content'] = media_tag * num_new_tags + inputs.messages[0]['content']
            elif num_new_tags < 0:
                logger.warning(
                    f'num_media: {num_media}, num_media_tags: {num_media_tags}, total_content: {total_content}. '
                    'We will only replace the frontmost media_tags while keeping the subsequent media_tags.')

def _encode_context_list(self,
                         context_list: List[Context],
                         loss_scale_list: Optional[List[float]] = None) -> Tuple[List[int], List[int], List[float]]:
    is_binary_loss_scale = self.is_binary_loss_scale
    if is_binary_loss_scale is None:
        is_binary_loss_scale = self.loss_scale.is_binary_loss_scale
    input_ids: List[int] = []
    labels: List[int] = []
    loss_scale: List[float] = []
    if loss_scale_list is None:
        loss_scale_list = [0.] * len(context_list)
    for i, (context, loss_weight) in enumerate(zip(context_list, loss_scale_list)):
        if isinstance(context, str):
            token_list = self._tokenize(context)
        else:
            token_list = context
        input_ids += token_list
        if loss_scale_list[i] > 0.0:
            labels += token_list
        else:
            labels += [-100] * len(token_list)
        if not is_binary_loss_scale:
            loss_scale.extend([loss_weight] * len(token_list))
    if is_binary_loss_scale:
        loss_scale = None
    return input_ids, labels, loss_scale

@staticmethod
def _add_dynamic_eos(input_ids: List[int], labels: List[int], loss_scale: Optional[List[int]],
                     suffix_tokens_id: List[int]) -> None:
    suffix_len = len(suffix_tokens_id)
    start = 0
    for i in range(1, len(labels) + 1):
        if labels[i - 1] >= 0 and i < len(labels) and labels[i] == -100:
            start = i
        elif start > 0 and labels[i - 1] == -100 and (i == len(labels) or labels[i] >= 0):
            # [0, 1, 2, -100(start), -100, 3(i), 4]
            length = i - start
            if length >= suffix_len and input_ids[start:start + suffix_len] == suffix_tokens_id:
                labels[start:start + suffix_len] = suffix_tokens_id
                if loss_scale and loss_scale[start:start + suffix_len] == [0] * suffix_len:
                    loss_scale[start:start + suffix_len] = [1] * suffix_len

